"""Efficient data helpers."""


def common_elements(a, b):
    """Return the sorted, unique values that occur in both inputs.

    The normal (hashable-value) path uses sets, rather than repeatedly
    scanning either input.  The fallback retains the original behaviour for
    inputs containing unhashable values.
    """
    try:
        in_b = set(b)
        # Building this set also lets us avoid a partially processed result
        # should an item in ``a`` be unhashable.
        set(a)
    except TypeError:
        out = []
        for x in a:
            if x in b and x not in out:
                out.append(x)
        return sorted(out)

    # A set intersection is enough: the requested result is unique and
    # sorted, so neither input order nor duplicate counts matter.
    return sorted(set(a).intersection(in_b))


def fib(n):
    """Return the nth Fibonacci number."""
    # Preserve the former function's behaviour for negative inputs too.
    if n < 2:
        return n
    previous, current = 0, 1
    for _ in range(n):
        previous, current = current, previous + current
    return previous


def count_pairs(nums, target):
    """Count index pairs whose values sum to ``target``."""
    # When reading x, every earlier occurrence of target-x forms one pair
    # with it.  Thus duplicates are counted correctly without nested loops.
    seen = {}
    count = 0
    for value in nums:
        count += seen.get(target - value, 0)
        seen[value] = seen.get(value, 0) + 1
    return count


def dedupe_keep_order(items):
    """Remove duplicates while retaining each value's first occurrence."""
    # Check hashability up front so the fallback exactly supports the broad
    # list-membership semantics of the original implementation.
    try:
        seen = set(items)
    except TypeError:
        out = []
        for value in items:
            if value not in out:
                out.append(value)
        return out

    seen.clear()
    out = []
    for value in items:
        if value not in seen:
            seen.add(value)
            out.append(value)
    return out

